mapper.select:
SELECT a.id, a.patient_id, p.name AS patient_name, a.doctor_id, d.name AS doctor_name, a.schedule_id, s.work_date, s.shift_type, a.status, a.create_time FROM appointment a LEFT JOIN patient p ON a.patient_id = p.id LEFT JOIN doctor d ON a.doctor_id = d.id LEFT JOIN doctor_schedule s ON a.schedule_id = s.id
AND a.patient_id = #{query.patientId}
AND a.doctor_id = #{query.doctorId}
AND a.status = #{query.status}
AND DATE(a.create_time) >= #{query.startDate}
AND DATE(a.create_time) <= #{query.endDate}
ORDER BY a.create_time DESC
